import{Logger}from './shared/logger.js';const EmptyStates={templates:{noData:{icon: 'inbox',title: 'Chưa có dữ liệu',description: 'Dữ liệu sẽ xuất hiện khi có thông tin mới.',action: null},noResults:{icon: 'search_off',title: 'Không tìm thấy kết quả',description: 'Thử lại với từ khóa khác hoặc xóa bộ lọc.',action:{label: 'Xóa bộ lọc',onClick:()=>window.location.reload()}},noCampaigns:{icon: 'campaign',title: 'Chưa có chiến dịch',description: 'Tạo chiến dịch marketing đầu tiên của bạn.',action:{label: 'Tạo chiến dịch',onClick:()=>window.location.href='/admin/campaigns.html?action=new'}},noLeads:{icon: 'person_add',title: 'Chưa có leads',description: 'Thêm leads để bắt đầu quản lý khách hàng tiềm năng.',action:{label: 'Thêm lead',onClick:()=>window.location.href='/admin/leads.html?action=new'}},noProjects:{icon: 'folder',title: 'Chưa có dự án',description: 'Tạo dự án mới để bắt đầu.',action:{label: 'Tạo dự án',onClick:()=>window.location.href='/portal/projects.html?action=new'}},noInvoices:{icon: 'receipt',title: 'Chưa có hóa đơn',description: 'Hóa đơn sẽ xuất hiện khi có giao dịch.',action:{label: 'Tạo hóa đơn',onClick:()=>window.location.href='/portal/invoices.html?action=new'}},noNotifications:{icon: 'notifications_none',title: 'Không có thông báo',description: 'Bạn đã xem tất cả thông báo.',action: null},noReports:{icon: 'analytics',title: 'Chưa có báo cáo',description: 'Báo cáo sẽ được tạo khi có dữ liệu phân tích.',action:{label: 'Tạo báo cáo',onClick:()=>window.location.href='/admin/reports.html?action=new'}},noMessages:{icon: 'mail_outline',title: 'Hộp thư rỗng',description: 'Không có tin nhắn nào.',action:{label: 'Soạn tin nhắn',onClick:()=>{}}},noTasks:{icon: 'task_alt',title: 'Không có nhiệm vụ',description: 'Tất cả nhiệm vụ đã hoàn thành!',action:{label: 'Tạo nhiệm vụ',onClick:()=>{}}},offline:{icon: 'cloud_off',title: 'Không có kết nối',description: 'Kiểm tra kết nối internet của bạn.',action:{label: 'Thử lại',onClick:()=>window.location.reload()}},error:{icon: 'error_outline',title: 'Có lỗi xảy ra',description: 'Vui lòng thử lại sau.',action:{label: 'Tải lại',onClick:()=>window.location.reload()}},loading:{icon: 'progress_activity',title: 'Đang tải...',description: 'Vui lòng chờ trong giây lát.',action: null},noAIContent:{icon: 'auto_awesome',title: 'Chưa có nội dung AI',description: 'Tạo nội dung đầu tiên với AI của bạn.',action:{label: 'Tạo với AI',onClick:()=>{const event=new CustomEvent('ai-generate-request');window.dispatchEvent(event);}}},noAIInsights:{icon: 'psychology',title: 'Chưa có insights AI',description: 'AI sẽ phân tích dữ liệu và đề xuất insights.',action:{label: 'Phân tích ngay',onClick:()=>{const event=new CustomEvent('ai-analyze-request');window.dispatchEvent(event);}}},noWidgets:{icon: 'dashboard',title: 'Chưa có widget',description: 'Thêm widget để tùy chỉnh dashboard của bạn.',action:{label: 'Thêm widget',onClick:()=>{const event=new CustomEvent('widget-add-request');window.dispatchEvent(event);}}},noAnalytics:{icon: 'analytics',title: 'Chưa có dữ liệu phân tích',description: 'Kết nối nguồn dữ liệu để xem phân tích.',action:{label: 'Kết nối nguồn',onClick:()=>window.location.href='/admin/integrations.html'}},noEvents:{icon: 'event',title: 'Không có sự kiện',description: 'Không có sự kiện nào trong lịch.',action:{label: 'Tạo sự kiện',onClick:()=>window.location.href='/admin/events.html?action=new'}},noContent:{icon: 'edit_calendar',title: 'Chưa có nội dung',description: 'Lên lịch nội dung cho mạng xã hội.',action:{label: 'Lên lịch bài viết',onClick:()=>window.location.href='/admin/content-calendar.html?action=new'}},noFiles:{icon: 'folder_open',title: 'Không có file',description: 'Tải lên file đầu tiên của bạn.',action:{label: 'Tải file lên',onClick:()=>{}}},noIntegrations:{icon: 'extension',title: 'Chưa có tích hợp',description: 'Kết nối các công cụ yêu thích của bạn.',action:{label: 'Khám phá tích hợp',onClick:()=>window.location.href='/admin/integrations.html'}}},render(container,type,custom={}){const el=typeof container==='string' ? document.querySelector(container): container;if(!el){Logger.warn(`Empty state container "${container}" not found`);return;}const template=this.templates[type]||this.templates.noData;const state={...template,...custom};el.innerHTML=`<div class="empty-state"><div class="empty-state-icon"><span class="material-symbols-outlined">${state.icon}</span></div><h3 class="empty-state-title">${state.title}</h3><p class="empty-state-description">${state.description}</p>${state.action ? `<button class="empty-state-action btn btn-filled"><span class="material-symbols-outlined">add</span>${state.action.label}</button>` : ''}</div>`;if(state.action){el.querySelector('.empty-state-action').onclick=state.action.onClick;}return el;},showOverlay(type,custom={}){const existing=document.querySelector('.empty-state-overlay');if(existing)existing.remove();const overlay=document.createElement('div');overlay.className='empty-state-overlay';const template=this.templates[type]||this.templates.noData;const state={...template,...custom};overlay.innerHTML=`<div class="empty-state-overlay-content"><span class="material-symbols-outlined">${state.icon}</span><h3>${state.title}</h3><p>${state.description}</p>${state.action ? `<button class="btn btn-filled">${state.action.label}</button>` : ''}</div>`;document.body.appendChild(overlay);if(state.action){overlay.querySelector('button').onclick=state.action.onClick;}return overlay;},hideOverlay(){const overlay=document.querySelector('.empty-state-overlay');if(overlay)overlay.remove();}};if(typeof document!=='undefined'){document.addEventListener('DOMContentLoaded',()=>{document.querySelectorAll('table').forEach(table=>{const tbody=table.querySelector('tbody');if(tbody&&!tbody.querySelector('tr:not(.empty)')){const path=window.location.pathname;let type='noData';if(path.includes('campaigns'))type='noCampaigns';else if(path.includes('leads'))type='noLeads';else if(path.includes('projects'))type='noProjects';else if(path.includes('invoices'))type='noInvoices';else if(path.includes('reports'))type='noReports';table.style.display='none';const emptyContainer=document.createElement('div');table.parentElement.appendChild(emptyContainer);EmptyStates.render(emptyContainer,type);}});});}export default EmptyStates;